import React, { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check for stored user data on app load
    const storedUser = localStorage.getItem('user');
    if (storedUser) {
      const userData = JSON.parse(storedUser);
      setUser(userData);
      setIsAuthenticated(true);
    }
    setLoading(false);
  }, []);

  const login = async (email, password, role) => {
    try {
      // Email-based routing logic
      let userRole = role;
      let companyName = '';
      let userName = '';

      if (email.toLowerCase() === 'eathealthy@gmail.com') {
        userRole = 'food';
        companyName = 'Fresh Foods Inc.';
        userName = 'Food Company Manager';
      } else if (email.toLowerCase() === 'techsolutions@gmail.com') {
        userRole = 'it';
        companyName = 'Tech Solutions Pro';
        userName = 'IT Solutions Manager';
      } else if (role === 'admin') {
        userRole = 'admin';
        companyName = 'VaultSphere';
        userName = 'System Administrator';
      } else {
        // Default client role
        userRole = 'client';
        companyName = 'Client Company';
        userName = 'Client User';
      }

      // Simulate API call - replace with actual authentication
      const mockUser = {
        id: Date.now(),
        email,
        role: userRole,
        name: userName,
        company: companyName
      };

      setUser(mockUser);
      setIsAuthenticated(true);
      localStorage.setItem('user', JSON.stringify(mockUser));
      
      return { success: true, user: mockUser };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const signup = async (email, password, role, companyName) => {
    try {
      // Simulate API call - replace with actual registration
      const mockUser = {
        id: Date.now(),
        email,
        role: 'client',
        name: companyName,
        company: companyName
      };

      setUser(mockUser);
      setIsAuthenticated(true);
      localStorage.setItem('user', JSON.stringify(mockUser));
      
      return { success: true, user: mockUser };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const logout = () => {
    setUser(null);
    setIsAuthenticated(false);
    localStorage.removeItem('user');
  };

  const value = {
    user,
    isAuthenticated,
    loading,
    login,
    signup,
    logout
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};
